import React from 'react';
import ReactLogo from '../assets/react.png';
import nodejs from '../assets/nodejs.png';
import git from '../assets/git.png';
import css from '../assets/css.svg';
import expo from '../assets/expo.png';
import xcode from '../assets/xcode.png';
import firebase from '../assets/firebase.svg';
import clinicjsdoctor from '../assets/clinicjsdoctor.png';
import tailwind from '../assets/tailwind.png';
import flask from '../assets/flask.png';
import mongodb from '../assets/mongodb.png';
import docker from '../assets/docker.png';
import pytest from '../assets/pytest.png';
import githubactions from '../assets/githubactions.png';

import './Tools.css';

const Tools = () => {
    return (
        <div className="toolsContainer">

            <div className="toolGroup">
                <h3 className="toolTitle">Frontend</h3>
                <div className="iconGrid">
                    <div className="iconItem"><img src={ReactLogo} alt="React" className="iconImage" /><p className="iconLabel">React</p></div>
                    <div className="iconItem"><img src={ReactLogo} alt="React Native" className="iconImage" /><p className="iconLabel">React Native</p></div>
                    <div className="iconItem"><img src={tailwind} alt="TailwindCSS" className="iconImage" /><p className="iconLabel">TailwindCSS</p></div>
                    <div className="iconItem"><img src={css} alt="CSS" className="iconImage" /><p className="iconLabel">CSS</p></div>
                    <div className="iconItem"><img src={expo} alt="Expo" className="iconImage" /><p className="iconLabel">Expo</p></div>
                </div>
            </div>

            <div className="toolGroup">
                <h3 className="toolTitle">Backend</h3>
                <div className="iconGrid">
                    <div className="iconItem"><img src={nodejs} alt="Node.js" className="iconImage" /><p className="iconLabel">Node.js</p></div>
                    <div className="iconItem"><img src={flask} alt="Flask" className="iconImage" /><p className="iconLabel">Flask</p></div>
                    <div className="iconItem"><img src={mongodb} alt="MongoDB" className="iconImage" /><p className="iconLabel">MongoDB</p></div>
                    <div className="iconItem"><img src={firebase} alt="Firebase" className="iconImage" /><p className="iconLabel">Firebase</p></div>
                </div>
            </div>

            <div className="toolGroup">
                <h3 className="toolTitle">DevOps & Tools</h3>
                <div className="iconGrid">
                    <div className="iconItem"><img src={docker} alt="Docker" className="iconImage" /><p className="iconLabel">Docker</p></div>
                    <div className="iconItem"><img src={git} alt="Git" className="iconImage" /><p className="iconLabel">Git</p></div>
                    <div className="iconItem"><img src={githubactions} alt="GitHub Actions" className="iconImage" /><p className="iconLabel">GitHub Actions</p></div>
                    <div className="iconItem"><img src={pytest} alt="pytest" className="iconImage" /><p className="iconLabel">pytest</p></div>
                </div>
            </div>

            <div className="toolGroup">
                <h3 className="toolTitle">Native / Other</h3>
                <div className="iconGrid">
                    <div className="iconItem"><img src={xcode} alt="Xcode" className="iconImage" /><p className="iconLabel">Xcode</p></div>
                    <div className="iconItem"><img src={clinicjsdoctor} alt="Clinic.js Doctor" className="iconImage" /><p className="iconLabel">Clinic.js</p></div>
                </div>
            </div>

        </div>
    );
};

export default Tools;
